{
  "mode": "io",
  "tests": [
    {
      "name": "basic_case",
      "input": "1 2\n3 4\n",
      "output": "10\n",
      "notes": "Basic addition of two pairs."
    },
    {
      "name": "negative_numbers",
      "input": "-1 -2\n-3 -4\n",
      "output": "-10\n",
      "notes": "Handles negative numbers correctly."
    },
    {
      "name": "zero_case",
      "input": "0 0\n0 0\n",
      "output": "0\n",
      "notes": "Tests the edge case of all zeros."
    },
    {
      "name": "large_numbers",
      "input": "1000000 2000000\n3000000 4000000\n",
      "output": "10000000\n",
      "notes": "Tests handling of large integers."
    },
    {
      "name": "single_pair",
      "input": "5 5\n",
      "output": "10\n",
      "notes": "Tests the case with a single pair of numbers."
    },
    {
      "name": "mixed_signs",
      "input": "5 -5\n-3 3\n",
      "output": "0\n",
      "notes": "Tests the case with mixed positive and negative numbers."
    },
    {
      "name": "multiple_pairs",
      "input": "1 1\n2 2\n3 3\n4 4\n",
      "output": "20\n",
      "notes": "Tests the case with multiple pairs."
    },
    {
      "name": "adversarial_case",
      "input": "1000000000 1000000000\n1000000000 1000000000\n",
      "output": "4000000000\n",
      "notes": "Tests the upper limit of integer values."
    }
  ],
  "assumptions": "Input will always be valid integers.",
  "notes": "Ensure to handle both positive and negative integers."
}
